-- Africa admin1 build-out (rev2): subdivisions for 55 countries. ZA already loaded; EH + 3 non-ISO disputed stay bare.
-- Guinea limited to regions+governorate (prefectures=admin2, deferred). Mozambique 'Maputo' city disambiguated to 'Maputo City'.
-- Source: dr5hn/countries-states-cities-database (ODbL) -> requires /attributions entry
ON CONFLICT (id) DO NOTHING;

-- Flip is_leaf on any African country that now has children
UPDATE atoms a SET is_leaf=false, updated_at=now()
WHERE a.realm_id='geography' AND a.depth=4 AND a.path LIKE 'Geography / Countries / Africa / %'
  AND EXISTS (SELECT 1 FROM atoms c WHERE c.path LIKE a.path || ' / %');